// Receives output from WF1-B (extracted sections) and the initial summary from WF1-A
// Combines into Supabase-ready format

const sections = $input.first().json;
const reportId = sections.report_id;

// Get initial summary from the WF1-A output (stored in the previous node's data)
const initialSummaryRaw = $('Call WF1-A Initial Summary').first().json.summary_text || '';

// Clean up initial summary - remove markdown formatting, convert to HTML
let initialSummaryContent = initialSummaryRaw
  .replace(/###\s*\*\*([^*]+)\*\*/g, '<h5>$1</h5>')
  .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
  .replace(/\*([^*]+)\*/g, '$1')
  .trim();

// Define all sections
const allSections = [
  {
    section_type: 'init_summary',
    title: 'Initial Summary',
    content: initialSummaryContent,
    isRawContent: true
  },
  { 
    section_type: 'approach', 
    title: sections.approach_title,
    content: sections.approach 
  },
  { 
    section_type: 'strengths', 
    title: sections.strengths_title,
    content: sections.strengths 
  },
  { 
    section_type: 'development', 
    title: sections.development_title,
    content: sections.development 
  },
  { 
    section_type: 'values', 
    title: sections.values_title,
    content: sections.values 
  }
];

// Process each section
return allSections
  .filter(s => s.content && (s.isRawContent || (Array.isArray(s.content) && s.content.length > 0)))
  .map(s => {
    let formatted;

    if (s.isRawContent) {
      formatted = s.content;
    } else {
      formatted = s.content.map(block => {
        const subheader = block.subheader && block.subheader.trim() 
          ? `<h5>${block.subheader}</h5>\n\n` 
          : '';
        const text = block.content || '';
        return `${subheader}${text}`;
      }).join('\n\n');
    }

    return {
      json: {
        report_id: reportId,
        section_type: s.section_type,
        title: s.title,
        content: formatted
      }
    };
  });
